#include <stdio.h>
#include <time.h>
#include <math.h>

#include "common.h"

#define BS 16

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

static void lud_diagonal_cuda (float* a, int size, int offset)
{
    int i, j, k;
    for (i = 0; BS > i; i++) {

        for (j = i; BS > j; j++) {
            for (k = 0; i > k ; k++) {
                AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
            }
        }

        float elem_1 = 1.f/AA(i,i);
        for (j = i+1; BS > j; j++) {
            for (k = 0; i > k ; k++) {
                AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
            }
            AA(j,i) = AA(j,i)*elem_1;
        }
    }

}

__global__ void lud_upper_kernel(float *a, int size, int offset, int x_0)
