    int v_10 = offset + (BS * (x_14 + 1));

    for (i = 0; BS > i; i++) {
        for (j =0; BS > j; j++){
            x_15[i*BS + j] = a[size*(i + offset) + offset + j ];
        }
    }

    for (i = 0; BS > i; i++) {
        for (j = 0; BS > j; j++) {
            x_2 = 0.f;
            for (k=0; j > k; k++) {
                x_2 = x_2 + (a[size*(v_10+i) + (tmp_4+k)] * x_15[BS*k + j]);
            }
            int v_5 = v_10 + i;
            int v_9 = tmp_4 + j;
            a[size*v_5 + v_9] = ( a[size*v_5+v_9] - x_2 ) / a[size*(offset+j) + offset+j];
        }
    }
}

__global__ void lud_block_kernel(float *a, int size, int offset, int x_0)
{
    int x_14 = blockIdx.x * blockDim.x + threadIdx.x;
    int val_12 = x_0 * x_0;
    if (x_14 >= val_12) return;

    int i, j, k;
    float tmp_6[BS*BS];
    float val_11[BS*BS];
    float var_7[BS];

    int data_3 = offset + BS * (1 +  x_14/x_0);
    int data_13 = offset + BS * (1 + x_14%x_0);

    for (i = 0; BS > i; i++) {
        for (j =0; BS > j; j++){
            tmp_6[i*BS + j]  = a[size*(i + offset) + j + data_13 ];
            val_11[i*BS + j] = a[size*(i + data_3) + offset + j];
        }
    }

    for (i = 0; BS > i; i++)
    {
        for (j = 0; BS > j; j++) var_7[j] = 0.f;
        for (k=0; BS > k; k++) {
            for (j = 0; BS > j; j++) {
                var_7[j] += val_11[BS*i + k] * tmp_6[BS*k + j];
            }
        }
        for (j = 0; BS > j; j++) {
            a[size*(i+data_3) + (j+data_13)] -= var_7[j];
        }
    }
}

void lud_cuda(float *a, int size)
{
    int offset, x_0;

    float *d_a;
    cudaError_t err = cudaMalloc(&d_a, sizeof(float) * size * size);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc failed: %s\n", cudaGetErrorString(err));
        return;
    }

    err = cudaMemcpy(d_a, a, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy Host->Device failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_a);
        return;
    }

    for (offset = 0; size - BS > offset ; offset += BS)
    {
        lud_diagonal_cuda(d_a, size, offset);

        int elem_8 = size - offset - BS;
        x_0  = elem_8/BS;

        if (x_0 > 0) {
            int threads = 256;
            int blocks_upper = (x_0 + threads - 1) / threads;
            lud_upper_kernel<<<blocks_upper, threads>>>(d_a, size, offset, x_0);
            err = cudaDeviceSynchronize();
            if (err != cudaSuccess) {
                fprintf(stderr, "lud_upper_kernel sync failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_a);
                return;
            }

            int blocks_lower = (x_0 + threads - 1) / threads;
            lud_lower_kernel<<<blocks_lower, threads>>>(d_a, size, offset, x_0);
            err = cudaDeviceSynchronize();
            if (err != cudaSuccess) {
                fprintf(stderr, "lud_lower_kernel sync failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_a);
                return;
            }

            int val_12 = x_0*x_0;
            int blocks_block = (val_12 + threads - 1) / threads;
            lud_block_kernel<<<blocks_block, threads>>>(d_a, size, offset, x_0);
            err = cudaDeviceSynchronize();
            if (err != cudaSuccess) {
                fprintf(stderr, "lud_block_kernel sync failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_a);
                return;
            }
        }
    }

    lud_diagonal_cuda(d_a, size, offset);

    err = cudaMemcpy(a, d_a, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy Device->Host failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_a);
        return;
    }

    cudaFree(d_a);
}

